以下是使用令牌桶算法实现网络限速100KB每秒的C++代码示例：

```cpp
#include <iostream>
#include <chrono>
#include <thread>
#include <mutex>
#include <condition_variable>

class TokenBucket {
private:
    double rate_; // 每秒产生的令牌数
    double capacity_; // 令牌桶容量
    double tokens_; // 当前令牌数
    std::mutex mutex_;
    std::condition_variable cv_;

public:
    TokenBucket(double rate, double capacity): rate_(rate), capacity_(capacity), tokens_(capacity) {}

    void refill() {
        std::unique_lock<std::mutex> lock(mutex_);
        tokens_ = capacity_;
        cv_.notify_all();
    }

    bool getToken(double tokens) {
        std::unique_lock<std::mutex> lock(mutex_);
        if (tokens_ < tokens) {
            return false;
        }
        tokens_ -= tokens;
        return true;
    }

    void consume(double tokens) {
        std::this_thread::sleep_for(std::chrono::milliseconds(static_cast<int>(tokens * 1000 / rate_)));
    }

    void limitRate(double dataSize) {
        while (!getToken(dataSize)) {
            std::this_thread::sleep_for(std::chrono::milliseconds(100));
        }
    }
};

int main() {
    double rate = 100000;  // 100KB每秒
    double capacity = 100000;  // 100KB
    double dataSize = 1024;  // 1KB

    TokenBucket tokenBucket(rate, capacity);

    // 产生令牌线程
    std::thread refillThread([&]() {
        while (true) {
            std::this_thread::sleep_for(std::chrono::seconds(1));
            tokenBucket.refill();
        }
    });

    // 模拟数据发送线程
    std::thread sendThread([&]() {
        while (true) {
            tokenBucket.limitRate(dataSize);
            std::cout << "Sending " << dataSize / 1024 << "KB" << std::endl;

            // 这里可以实现网络发送逻辑，此处只简单模拟等待
            std::this_thread::sleep_for(std::chrono::milliseconds(500));
        }
    });

    refillThread.join();
    sendThread.join();

    return 0;
}
```

上述代码中，TokenBucket类用于实现令牌桶算法，其中refill()函数用于每秒周期性地填充令牌桶，getToken()函数用于获取一定数量的令牌，consume()函数用于消耗令牌，limitRate()函数用于限制数据发送速率。主函数创建了两个线程，refillThread用于周期性填充令牌桶，sendThread用于模拟数据发送，同时限制发送速率。

为了输出限制后的实际发送速度，可以在发送数据的线程中增加一些计时和输出的代码。下面是修改后的示例代码：

