#include <iostream>
#include <chrono>
#include <thread>
#include <mutex>
#include <condition_variable>

class RateLimiter {
private:
    double rate_; // 限速速率（单位：字节/秒）
    double capacity_; // 令牌桶容量（单位：字节）
    double tokens_; // 当前令牌数量（单位：字节）
    std::mutex mutex_;
    std::condition_variable cv_;

public:
    RateLimiter(double rate, double capacity): rate_(rate), capacity_(capacity), tokens_(capacity) {}

    void limitRate(double dataSize) {
        std::unique_lock<std::mutex> lock(mutex_);

        // 等待令牌桶中有足够的令牌
        cv_.wait(lock, [this, dataSize] { return tokens_ >= dataSize; });

        // 令牌数量减少
        tokens_ -= dataSize;
    }

    void refillTokens() {
        std::unique_lock<std::mutex> lock(mutex_);

        // 重新填充令牌
        tokens_ = std::min(capacity_, tokens_ + rate_);

        // 通知限速线程可以继续发送数据
        cv_.notify_all();
    }
};

// 限速线程（每秒发送1KB）
void sendThreadFunction(RateLimiter& limiter) {
    double dataSize = 1024; // 每次发送的数据大小（单位：字节）

    while (true) {
        limiter.limitRate(dataSize);
        std::cout << "Sending " << dataSize / 1024 << "KB" << std::endl;

        // 这里可以实现网络发送逻辑，此处只简单模拟等待
        std::this_thread::sleep_for(std::chrono::milliseconds(500));
    }
}

// 填充令牌线程（每秒产生100KB的令牌）
void refillThreadFunction(RateLimiter& limiter) {
    double refillRate = 100000; // 令牌填充速率（单位：字节/秒）

    while (true) {
        limiter.refillTokens();
        std::this_thread::sleep_for(std::chrono::seconds(1));
    }
}

int main() {
    double rate = 1000; // 限速速率：1KB/s
    double capacity = 1000; // 令牌桶容量：1KB

    RateLimiter limiter(rate, capacity);

    // 创建限速线程和填充令牌线程，并启动它们
    std::thread sendThread(sendThreadFunction, std::ref(limiter));
    std::thread refillThread(refillThreadFunction, std::ref(limiter));

    // 等待线程结束
    sendThread.join();
    refillThread.join();

    return 0;
}
```

